4785	\begin{lemma}\leanok
4786	[Leg-(B) unit \(\varepsilon\) is invertible, \(\mathrm{inv}\)-direction]
4787	  \label{lem:isiso_eps_restrictscalars_appiso}
4788	  \lean{AlgebraicGeometry.Scheme.Modules.isIso_ε_restrictScalars_appIso}
4789	  \uses{def:restrict_scalars_lax_epsilon}
4790	  Let \(f : Y \hookrightarrow X\) be an open immersion and \(W' \subseteq Y\) an open. The
4791	  lax-monoidal unit \(\varepsilon\) of the change-of-rings functor
4792	  \(\mathtt{restrictScalars}\,\bigl((f.\mathtt{appIso}\,W').\mathrm{inv}.\mathrm{hom}\bigr)\),
4793	  taken along the \(\mathtt{CommRingCat}\)-level structure-ring isomorphism, is an
4794	  isomorphism.
4795	\end{lemma}
4796	\begin{proof}
4797	  \uses{def:restrict_scalars_lax_epsilon}
4798	  Proved directly in Lean --- the underlying ring map
4799	  \((f.\mathtt{appIso}\,W').\mathrm{inv}.\mathrm{hom}\) is an isomorphism, hence bijective, so
4800	  its restriction-of-scalars unit \(\varepsilon\) (\cref{def:restrict_scalars_lax_epsilon}) is
4801	  invertible by the bijectivity criterion for \(\varepsilon\).
4802	\end{proof}
